mapper.select:
SELECT BOARD_NO, TITLE, CONTENT, WRITER, REG_DATE, UPD_DATE
FROM BOARD
WHERE BOARD_NO = #{boardNo}

mapper.update:
UPDATE BOARD
SET TITLE = #{title},
CONTENT = #{content},
UPD_DATE = SYSDATE
WHERE BOARD_NO = #{boardNo}
AND WRITER = #{writer}

mapper.delete:
DELETE FROM BOARD
WHERE BOARD_NO = #{boardNo}
AND WRITER = #{writer}
